def remove_seam(img, seam):
    if img.dim() == 2:
        H, W = img.shape
        mask = torch.ones(H, W, dtype=torch.bool)
        for i in range(H):
            mask[i, seam[i]] = False
        return img[mask].reshape(H, W-1)
    else:
        H, W, C = img.shape
        mask = torch.ones(H, W, dtype=torch.bool)
        for i in range(H):
            mask[i, seam[i]] = False
        return img[mask.unsqueeze(-1).expand_as(img)].reshape(H, W-1, C)

